19	// ─── Minimal test framework ────────────────────────────────────────────────────
20	
21	int passed = 0, failed = 0;
22	var failures = new List<string>();
23	
24	void AssertTrue(bool condition, string message)
25	{
26	    if (condition) { passed++; Console.WriteLine($"  ✓ {message}"); }
27	    else { failed++; failures.Add(message); Console.WriteLine($"  ✗ {message}"); }
28	}
29	
30	void AssertEqual<T>(T expected, T actual, string message)
31	{
32	    bool eq = EqualityComparer<T>.Default.Equals(expected, actual);
33	    if (!eq) message += $" (expected: {expected}, got: {actual})";
34	    AssertTrue(eq, message);
35	}
36	
37	void AssertApprox(decimal expected, decimal actual, string message, decimal tolerance = 0.01m)
38	{
39	    bool eq = Math.Abs(expected - actual) <= tolerance;
40	    if (!eq) message += $" (expected: {expected}, got: {actual})";
41	    AssertTrue(eq, message);
42	}
43	
44	string scriptDir = Directory.GetCurrentDirectory();
