46	// ═══════════════════════════════════════════════════════════════════════════════
47	// TEST SUITE
48	// ═══════════════════════════════════════════════════════════════════════════════
49	
50	Console.WriteLine("\n═══ CSV Report Generator — Test Suite ═══\n");
51	
52	// ── 1. CSV Parsing Tests ────────────────────────────────────────────────────────
53	Console.WriteLine("── CSV Parsing ──");
54	
55	// Test: Parse a single CSV row
56	{
57	    var employees = CsvParser.Parse(
58	        "name,department,salary,hire_date,status\nAlice,Engineering,90000,2020-01-01,active\n");
59	    AssertEqual(1, employees.Count, "Parse single row: count = 1");
60	    AssertEqual("Alice", employees[0].Name, "Parse single row: name = Alice");
61	    AssertEqual("Engineering", employees[0].Department, "Parse single row: department = Engineering");
62	    AssertEqual(90000m, employees[0].Salary, "Parse single row: salary = 90000");
63	    AssertEqual(new DateTime(2020, 1, 1), employees[0].HireDate, "Parse single row: hire_date");
64	    AssertEqual("active", employees[0].Status, "Parse single row: status = active");
65	}
66	
67	// Test: Parse multiple rows
68	{
69	    var employees = CsvParser.Parse(
70	        "name,department,salary,hire_date,status\nA,Eng,100000,2020-01-01,active\nB,Sales,80000,2021-06-15,inactive\n");
71	    AssertEqual(2, employees.Count, "Parse multiple rows: count = 2");
72	    AssertEqual("A", employees[0].Name, "Parse multiple rows: first = A");
73	    AssertEqual("B", employees[1].Name, "Parse multiple rows: second = B");
74	}
