149	// ── 3. Aggregation Tests ────────────────────────────────────────────────────────
150	Console.WriteLine("\n── Aggregation ──");
151	
152	var testEmps = CsvParser.Parse(
153	    "name,department,salary,hire_date,status\n" +
154	    "A,Eng,100000,2020-01-01,active\n" +
155	    "B,Eng,80000,2021-06-15,active\n" +
